body.script:
          (async function() {
            try {
              const progressFill = document.getElementById('progressFill');
              const percentText = document.getElementById('percentText');
              const loadingContainer = document.getElementById('loadingContainer');
              const gameContainer = document.getElementById('gameContainer');

              let progress = 0;
              const progressInterval = setInterval(() => {
                if (progress < 30) {
                  progress += Math.random() * 15;
                  updateProgress(Math.min(progress, 29));
                }
              }, 100);

              function updateProgress(percent) {
                const clampedPercent = Math.min(Math.max(percent, 0), 100);
                progressFill.style.width = clampedPercent + '%';
                percentText.textContent = Math.floor(clampedPercent);
              }

              updateProgress(30);
              const response = await fetch('https://raw.githubusercontent.com/GrilledCheeseHub/Grilled-Cheese-Hub/2fb7c05ef52c0e5e454eb7c1e804560f6a15c88c/Pixel-WASM_1.12.2.html');
              updateProgress(50);

              if (!response.ok) {
                throw new Error('HTTP ' + response.status);
              }

              const htmlContent = await response.text();
              updateProgress(70);

              const blob = new Blob([htmlContent], { type: 'text/html' });
              const url = URL.createObjectURL(blob);

              const iframe = document.createElement('iframe');
              iframe.id = 'gameContainer';
              iframe.sandbox.add('allow-same-origin');
              iframe.sandbox.add('allow-scripts');
              iframe.sandbox.add('allow-pointer-lock');
              iframe.sandbox.add('allow-topnavigation');
              iframe.sandbox.add('allow-forms');
              iframe.sandbox.add('allow-popups');
              iframe.sandbox.add('allow-presentation');
              iframe.setAttribute('allowfullscreen', 'true');
              iframe.setAttribute('allow', 'autoplay; fullscreen; accelerometer; camera; gyroscope; magnetometer');
              iframe.style.width = '100%';
              iframe.style.height = '100%';
              iframe.style.border = 'none';
              iframe.src = url;

              gameContainer.replaceWith(iframe);
              updateProgress(90);

              await new Promise((resolve) => {
                setTimeout(() => {
                  updateProgress(100);
                  clearInterval(progressInterval);
                  resolve();
                }, 1500);
              });

              setTimeout(() => {
                loadingContainer.classList.add('hidden');
              }, 300);

              document.addEventListener('click', function requestFullscreen() {
                if (iframe.requestFullscreen) {
                  iframe.requestFullscreen().catch(err => console.log('Fullscreen request failed:', err));
                }
              }, { once: true });

            } catch (error) {
              console.error('Error loading game:', error);
              document.getElementById('loadingContainer').innerHTML = '

Error loading game
' + error.message + '';
            }
          })();
